function addTab(){
  if (!$('#character').length){
    $('#bottomsidebar .idTabs li')
      .first()
      .after('<li><a href="#character">Status tracker</a></li>');

    $('#communication')
      .after('<div id="character" class="content" style="display: none; font-size: 14px;"></div>');

    $('#bottomsidebar .idTabs a').on('click', toggleTab);

    $('#character, #communication').css({
      overflow: 'auto',
      'scrollbar-width': 'none',
      '-ms-overflow-style': 'none'
    });

    $('#character, #communication')
      .append('<style>#character::-webkit-scrollbar{display:none;}</style>');
  }
}

function toggleTab(e) {
  e.preventDefault();

  const $tab = $(this);
  const target = $tab.attr('href'); 

  $('#bottomsidebar .content').hide(); 
  $('#bottomsidebar .idTabs a').removeClass('selected');

  $(target).show();
  $tab.addClass('selected');
}
