//output
function out(text, color = defaultcolor) {
  gwc.output.append(text, color);
}
//append with multiple colors
function cout(text1, color1 = "", text2 = "", color2 = "") {
  gwc.output.append(text1 + text2, color1);
  if (color2 && text2) {
    gwc.output.replace(text2, color(text2, color2));
  }
}
//Easier hmtl coloring
function color(text, color) {
  return `<span style="color:${color};">${text}</span>`;
}
//Chop decimals
function toWhole(num) {
  return Math.trunc(num);
}
//Bar function
function makeBar(percent, length = 20) {
  percent = Math.max(0, Math.min(100, percent));
  let filled = Math.round((percent / 100) * length);
  let empty = length - filled;
  let bar = "█".repeat(filled) + "-".repeat(empty);
  return `[${bar}] ${percent}%`;
}
//Amountifier
function fn(num) {
  if (num == null) return "0";
  return Number(num).toLocaleString();
}
// Easier args
function a(index, word) {
  return args[index] === word;
}
// Be sure numbers are numbers
function ISN(value) {
  const num = Number(value);
  if (!Number.isInteger(num)) return false;
  return num;
}
// Easier clickers
function ezlink(txt, cmd) {
  return { type: "cmd", text: txt, command: cmd };
}
// Easier colors
function ezcol(txt, colr = helpcolor){
  return { type: "color", text: txt, color: colr }
}
// Separator
function sep() {
  return ezcol("\n─────────────────────────────────────────\n");
}

// Clickable text
function click(...parts) {
  let output = "";
  parts.forEach((p, i) => {
    if (typeof p === "string") {
      output += p;
    } else if (p.type === "color") {
      output += `<span style="color:${p.color};">${p.text}</span>`;
    } else if (p.type === "cmd") {
      let id = "cmd_" + Date.now() + "_" + i;
      output += `<a href="#" id="${id}" style="display:inline; width:auto; color:${p.color || clickcolor}; text-decoration:none; border:none; padding:0; margin:0; cursor:pointer;">${p.text}</a>`;
      setTimeout(() => {
        let el = document.getElementById(id);
        if (el) {
          el.onclick = (e) => {
            e.preventDefault();
            gwc.connection.send(p.command, true);
          };
        }
      }, 0);
    } else if (p.type === "func") {
      let id = "func_" + Date.now() + "_" + i;
      output += `<a href="#" id="${id}" style="display:inline; width:auto; color:${p.color || helpcolor}; text-decoration:none; border:none; padding:0; margin:0; cursor:pointer;">${p.text}</a>`;
      setTimeout(() => {
        let el = document.getElementById(id);
        if (el) {
          el.onclick = (e) => {
            e.preventDefault();
            p.onClick();
          };
        }
      }, 0);
    }
  });
  gwc.output.append("REPLACEMENT TEXT");
  gwc.output.replace("REPLACEMENT TEXT", output);
}
