//Store current date in trax
function getDate() {
    const today = new Date().toLocaleDateString("en-CA", { 
      timeZone: timezone, 
      year: "numeric", 
      month: "2-digit", 
      day: "2-digit" 
    });
return today
  }

//Get date and time
function getDateTime(timeZone = "UTC") {
  const now = new Date();
  return new Intl.DateTimeFormat("en-US", {timeZone: timeZone, year: "numeric", month: "2-digit", day: "2-digit", hour: "2-digit", minute: "2-digit", hour12: false
    }).format(now);
  }

//Save date to storage
function saveDate() {
  const date = getDateTime(timezone);
  localStorage.setItem("LastSaved", date);
}

//Save local storage
function backupTrax() {
  let trax = gwc.userdata.trax;
  if (!trax) {
    out("No trax userdata to back up!");
  } else if (trax) {
    localStorage.setItem("traxBackup", JSON.stringify(trax));
    let saved = localStorage.getItem("traxBackup");
    let parsed = JSON.parse(saved);
    if (parsed && parsed.killz && parsed.coinloot) {
      out("Data successfully backed up!");
    }
  }
}

//Load local storage
function loadTrax() {
  let saved = localStorage.getItem("traxBackup");
  if (!saved) {
    out("No browser storage detected!", "red");
  } else if (saved) {
    let parsed = JSON.parse(saved);
    if (parsed && parsed.killz && parsed.coinloot) {
      gwc.userdata.trax = parsed;
      out("Data restored from backup!");
    }
  }
}

//Check local storage
function checkTrax() {
  let saved = localStorage.getItem("traxBackup");
  if (!saved) {
    out("No browser storage detected!");
  } else if (saved) {
    let parsed = JSON.parse(saved);
    if (parsed && parsed.killz && parsed.coinloot) {
      let savedDate = localStorage.getItem("LastSaved");
      out("Data is detected in storage! Date of save: " + savedDate);
    }
  }
}
